import { NextResponse } from 'next/server';
import crypto from 'crypto';
import Razorpay from 'razorpay';
import prisma from '../../../lib/prisma';

const razorpay = new Razorpay({
  key_id: process.env.RAZORPAY_KEY_ID || 'rzp_test_placeholder',
  key_secret: process.env.RAZORPAY_KEY_SECRET || 'placeholder_secret',
});

export async function POST(request) {
  try {
    const data = await request.json();
    console.log('--- Registration Attempt (Next.js) ---');
    
    if (!data.name || !data.email || !data.phone) {
      return NextResponse.json({ message: 'Missing required fields' }, { status: 400 });
    }

    // 1. Create Registration Record
    const registration = await prisma.registration.create({
      data: {
        registrantType: data.registrantType || 'Single',
        name: data.name,
        email: data.email,
        phone: data.phone,
        gender: data.gender,
        addressLine1: data.addressLine1,
        country: data.country,
        state: data.state,
        city: data.city,
        zipCode: data.zipCode,
        company: data.company,
        designation: data.designation,
        sector: data.sector,
        collegeName: data.collegeName,
        teamSize: data.teamSize ? parseInt(data.teamSize) : 1,
        memberNames: Array.isArray(data.memberNames) ? data.memberNames : [],
        participationType: data.participationType,
        fileName: data.fileName,
        fileData: data.fileData,
      },
    });

    // 2. Create Razorpay Order
    const amount = data.amount || 999;
    const options = {
      amount: Math.round(amount * 100),
      currency: 'INR',
      receipt: `receipt_${registration.id}`,
    };

    const order = await razorpay.orders.create(options);

    // 3. Save Order ID
    await prisma.payment.create({
      data: {
        razorpayOrderId: order.id,
        amount: parseFloat(amount),
        status: 'created',
        registrationId: registration.id,
      },
    });

    return NextResponse.json({
      orderId: order.id,
      registrationId: registration.id,
      amount: amount,
    });

  } catch (error) {
    console.error('Registration Error:', error);
    return NextResponse.json({ 
      message: 'Registration initialization failed',
      error: error.message 
    }, { status: 500 });
  }
}
